const d = $json;

const useCase = (d.use_case && d.use_case.length > 0)
  ? d.use_case.join(', ')
  : 'general automation';

const apps = (d.apps && d.apps.length > 0)
  ? d.apps.join(', ')
  : 'various integrations';

const difficulty = d.difficulty || 'unknown';

return {
  json: {
    pageContent: `
Template: ${d.name}

Description:
${d.description || ''}

Use Case:
${useCase}

Apps:
${apps}

Difficulty:
${difficulty}

Popularity:
${d.totalViews || 0}
    `.trim(),

    metadata: {
      id: d.id,
      name: d.name,
      views: d.totalViews || 0,
      apps: d.apps || [],
      use_case: d.use_case || [],
      difficulty: difficulty,
      template_url: `https://n8n.io/workflows/${d.id}`
    }
  }
};

const seen = new Set();

return items.filter(item => {
  const id = item.json.metadata?.id;

  // kalau tidak ada id, tetap lolos
  if (!id) return true;

  // kalau sudah pernah ada → buang
  if (seen.has(id)) return false;

  seen.add(id);
  return true;
});
